const raw = items[0].json.choices[0].message.content;
let profile;
try {
  const cleaned = raw.replace(/```json|```/g, '').trim();
  profile = JSON.parse(cleaned);
} catch(e) {
  profile = { name: 'Unknown', skills: [], domain: 'General', level: 'Internship', summary: raw };
}

// Store profile in workflow static data for later use
const staticData = this.getWorkflowStaticData('global');
staticData.profile = profile;
staticData.chatId = items[0].json._chatId || '';

return [{ json: { profile, success: true } }];

