const jobs = items[0].json.data || [];
const profile = $('Store Profile').item.json.profile;

// Basic scoring: keyword match against skills + domain
const scored = jobs.map(job => {
  const text = ((job.job_title || '') + ' ' + (job.job_description || '')).toLowerCase();
  const skillMatches = (profile.skills || []).filter(s => text.includes(s.toLowerCase())).length;
  const domainMatch = text.includes((profile.domain || '').toLowerCase()) ? 2 : 0;
  const levelMatch = text.includes('intern') ? 3 : 0;
  const score = skillMatches + domainMatch + levelMatch;
  return {
    title: job.job_title,
    company: job.employer_name,
    location: job.job_city + ', ' + job.job_country,
    url: job.job_apply_link,
    posted: job.job_posted_at_datetime_utc,
    description: (job.job_description || '').slice(0, 300),
    score
  };
});

const top5 = scored.sort((a,b) => b.score - a.score).slice(0, 5);
return top5.map(j => ({ json: j }));

