// Merge cover letter into job object
const coverLetter = items[0].json.choices[0].message.content;
const job = $('Score & Rank Jobs').item.json;

// Generate a short job ID for callback data
const jobId = Buffer.from(job.url || job.title).toString('base64').slice(0, 40);

// Save to static data tracker
const staticData = this.getWorkflowStaticData('global');
if (!staticData.pendingJobs) staticData.pendingJobs = {};
staticData.pendingJobs[jobId] = { ...job, coverLetter, status: 'pending', chatId: staticData.chatId };

return [{ json: { ...job, coverLetter, jobId } }];

const callbackData = items[0].json.callback_query.data;
const chatId = items[0].json.callback_query.message.chat.id;
const action = callbackData.startsWith('approve_') ? 'approve' :
               callbackData.startsWith('skip_') ? 'skip' : 'view';
const jobId = callbackData.split('_').slice(1).join('_');

return [{ json: { action, jobId, chatId, callbackQuery: items[0].json.callback_query } }];

const { jobId, chatId } = items[0].json;
const staticData = this.getWorkflowStaticData('global');
const job = (staticData.pendingJobs || {})[jobId];

if (!job) return [{ json: { success: false, message: 'Job not found in tracker' } }];

// Mark as approved
if (!staticData.appliedJobs) staticData.appliedJobs = [];
staticData.appliedJobs.push({
  ...job,
  status: 'applied',
  appliedAt: new Date().toISOString(),
  followUpDue: new Date(Date.now() + 7 * 24 * 60 * 60 * 1000).toISOString()
});
delete staticData.pendingJobs[jobId];

return [{ json: { job, chatId, success: true } }];

