const { jobId, chatId, action } = items[0].json;
const staticData = this.getWorkflowStaticData('global');
const job = (staticData.pendingJobs || {})[jobId];

if (action === 'view' && job) {
  return [{ json: { message: job.coverLetter, chatId, type: 'view' } }];
}
if (action === 'skip' && job) {
  job.status = 'skipped';
  return [{ json: { message: `⏭ Skipped *${job.title}* at *${job.company}*`, chatId, type: 'skip' } }];
}
return [{ json: { message: 'OK', chatId, type: 'unknown' } }];

const staticData = this.getWorkflowStaticData('global');
const now = new Date();
const applied = staticData.appliedJobs || [];

const due = applied.filter(j => {
  if (j.status !== 'applied') return false;
  const followUpDate = new Date(j.followUpDue);
  return followUpDate <= now;
});

if (due.length === 0) return [{ json: { skip: true } }];
return due.map(j => ({ json: j }));

