const followupEmail = items[0].json.choices[0].message.content;
const job = $('Find Follow-ups Due').item.json;

// Mark follow-up sent
const staticData = this.getWorkflowStaticData('global');
const applied = staticData.appliedJobs || [];
const idx = applied.findIndex(j => j.url === job.url);
if (idx !== -1) {
  applied[idx].status = 'followed_up';
  applied[idx].followedUpAt = new Date().toISOString();
}

return [{ json: { ...job, followupEmail, chatId: staticData.chatId } }];

const staticData = this.getWorkflowStaticData('global');
const profile = staticData.profile;
if (!profile) return [{ json: { skip: true, reason: 'No profile stored yet. Send resume first.' } }];
return [{ json: { profile, chatId: staticData.chatId } }];
